// The tag name is valid if it does not start with a dot or a hyphen and does not contain consecutive dots or hyphens.
// We can use a regular expression to match the valid characters in the tag name.
function isValidTag(tag) {
  if (!tag) return false;
  if (tag[0] === '.') return false;
  if (tag[0] === '-') return false;
  if (tag.includes('..') || tag.includes('--')) return false;
  let regex = /^[0-9a-zA-Z.-]+$/;
  if (!regex.test(tag)) return false;
  return true;
}

